/** Auto-generated from public/index.html — run: node scripts/embed.js */
module.exports = "<!DOCTYPE html>\n<html lang=\"ja\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>QR Magic（個人用）</title>\n  <style>\n    :root { font-family: system-ui, sans-serif; color: #111; background: #f4f4f5; }\n    body { margin: 0 auto; max-width: 520px; padding: 1rem 1rem 3rem; }\n    h1 { font-size: 1.15rem; margin: 0 0 0.75rem; }\n    h2 { font-size: 0.95rem; margin: 1.25rem 0 0.5rem; }\n    input[type=\"text\"], input[type=\"password\"], textarea, select {\n      width: 100%; box-sizing: border-box; padding: 0.5rem; font-size: 1rem; border: 1px solid #ccc; border-radius: 6px;\n    }\n    textarea { min-height: 2.5rem; resize: vertical; }\n    button {\n      cursor: pointer; border: none; border-radius: 8px; padding: 0.65rem 1rem; font-size: 0.95rem; font-weight: 600;\n    }\n    .btn-primary { background: #2563eb; color: #fff; }\n    .btn-secondary { background: #e4e4e7; color: #18181b; }\n    .btn-danger { background: #dc2626; color: #fff; }\n    .panel { background: #fff; border-radius: 10px; padding: 0.85rem; border: 1px solid #e4e4e7; margin-top: 0.75rem; }\n    .muted { color: #71717a; font-size: 0.85rem; word-break: break-all; }\n    .toolbar { display: flex; flex-wrap: wrap; gap: 0.5rem; margin-top: 0.5rem; }\n    .settingsFab {\n      position: fixed;\n      top: 0.55rem;\n      right: 0.55rem;\n      z-index: 80;\n      display: none;\n      align-items: center;\n      gap: 0.35rem;\n      padding: 0.45rem 0.75rem;\n      font-size: 0.88rem;\n      font-weight: 600;\n      border-radius: 999px;\n      background: #fff;\n      border: 1px solid #e4e4e7;\n      box-shadow: 0 1px 3px rgba(0,0,0,.08);\n      color: #18181b;\n    }\n    .settingsFab.settingsFab--visible { display: inline-flex; }\n    .settingsBackdrop {\n      display: none;\n      position: fixed;\n      inset: 0;\n      z-index: 90;\n      background: rgba(0,0,0,.32);\n    }\n    .settingsBackdrop.settingsBackdrop--open { display: block; }\n    .settingsDrawer {\n      display: none;\n      position: fixed;\n      top: 0;\n      right: 0;\n      bottom: 0;\n      width: min(100vw, 22rem);\n      z-index: 100;\n      background: #fff;\n      border-left: 1px solid #e4e4e7;\n      box-shadow: -4px 0 24px rgba(0,0,0,.1);\n      flex-direction: column;\n      overflow: hidden;\n    }\n    .settingsDrawer.settingsDrawer--open { display: flex; }\n    .settingsDrawerHead {\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      gap: 0.5rem;\n      padding: 0.85rem 1rem;\n      border-bottom: 1px solid #e4e4e7;\n      flex-shrink: 0;\n    }\n    .settingsDrawerHead h2 { font-size: 0.95rem; margin: 0; }\n    .settingsDrawerBody { padding: 0.85rem 1rem 1.25rem; overflow: auto; flex: 1; }\n    .settingsDrawerBody textarea { font-size: 0.72rem; font-family: ui-monospace, monospace; min-height: 12rem; }\n  </style>\n</head>\n<body>\n  <button type=\"button\" class=\"settingsFab\" id=\"btnOpenSettings\" aria-haspopup=\"dialog\" aria-expanded=\"false\" aria-controls=\"settingsDrawer\">\n    設定\n  </button>\n  <div class=\"settingsBackdrop\" id=\"settingsBackdrop\" aria-hidden=\"true\"></div>\n  <div class=\"settingsDrawer\" id=\"settingsDrawer\" role=\"dialog\" aria-modal=\"true\" aria-labelledby=\"settingsDrawerTitle\">\n    <div class=\"settingsDrawerHead\">\n      <h2 id=\"settingsDrawerTitle\">設定</h2>\n      <button type=\"button\" class=\"btn-secondary\" id=\"btnCloseSettings\" style=\"padding:0.4rem 0.65rem;font-size:0.82rem\">閉じる</button>\n    </div>\n    <div class=\"settingsDrawerBody\">\n      <h3 style=\"font-size:0.88rem;margin:0 0 .35rem\">有効な名刺用URL</h3>\n      <p id=\"settingsUrlMeta\" class=\"muted\" style=\"margin:0 0 0.5rem;font-size:0.8rem\"></p>\n      <div class=\"toolbar\" style=\"margin-top:0;margin-bottom:0.5rem\">\n        <button type=\"button\" class=\"btn-secondary\" id=\"btnRefreshUrlList\" style=\"font-size:0.85rem;padding:0.45rem 0.75rem\">一覧を更新</button>\n      </div>\n      <label class=\"muted\" for=\"settingsUrlList\" style=\"font-size:0.78rem\">1行1本（コピー可）</label>\n      <textarea id=\"settingsUrlList\" readonly rows=\"8\" style=\"margin-top:0.35rem\"></textarea>\n\n      <hr style=\"margin:0.9rem 0;border:none;border-top:1px solid #eee\" />\n      <h3 style=\"font-size:0.88rem;margin:0 0 .35rem\">アクセス履歴（簡易）</h3>\n      <p id=\"settingsHistoryMeta\" class=\"muted\" style=\"margin:0 0 0.5rem;font-size:0.8rem\"></p>\n      <div class=\"toolbar\" style=\"margin-top:0;margin-bottom:0.5rem\">\n        <button type=\"button\" class=\"btn-secondary\" id=\"btnRefreshHistory\" style=\"font-size:0.85rem;padding:0.45rem 0.75rem\">履歴を更新</button>\n      </div>\n      <label class=\"muted\" for=\"settingsHistoryList\" style=\"font-size:0.78rem\">URLごとの読取回数</label>\n      <textarea id=\"settingsHistoryList\" readonly rows=\"6\" style=\"margin-top:0.35rem\"></textarea>\n      <label class=\"muted\" for=\"settingsRecentEvents\" style=\"display:block;margin-top:.45rem;font-size:0.78rem\">直近の読取イベント（新しい順）</label>\n      <textarea id=\"settingsRecentEvents\" readonly rows=\"6\" style=\"margin-top:0.35rem\"></textarea>\n\n      <hr style=\"margin:0.9rem 0;border:none;border-top:1px solid #eee\" />\n      <h3 style=\"font-size:0.88rem;margin:0 0 .35rem\">QR一括画像ダウンロード</h3>\n      <p class=\"muted\" style=\"margin:0 0 0.5rem;font-size:0.8rem\">発行済み名刺URLをPNG化して ZIP で保存します。</p>\n      <div class=\"toolbar\" style=\"margin-top:0;margin-bottom:0.5rem\">\n        <button type=\"button\" class=\"btn-primary\" id=\"btnDownloadQrZip\" style=\"font-size:0.85rem;padding:0.45rem 0.75rem\">ZIPをダウンロード</button>\n      </div>\n\n      <div id=\"adminCodePanel\" style=\"display:none\">\n        <hr style=\"margin:0.9rem 0;border:none;border-top:1px solid #eee\" />\n        <h3 style=\"font-size:0.88rem;margin:0 0 .35rem\">配布用ログインID管理（管理者）</h3>\n        <p id=\"adminCodeMeta\" class=\"muted\" style=\"margin:0 0 0.5rem;font-size:0.8rem\"></p>\n        <div class=\"toolbar\" style=\"margin-top:0;margin-bottom:0.5rem\">\n          <input type=\"number\" id=\"adminIssueCount\" value=\"50\" min=\"1\" max=\"5000\" style=\"width:7rem\" />\n          <button type=\"button\" class=\"btn-primary\" id=\"btnAdminIssueCodes\" style=\"font-size:0.85rem;padding:0.45rem 0.75rem\">IDを一括発行</button>\n          <button type=\"button\" class=\"btn-secondary\" id=\"btnAdminRefreshCodes\" style=\"font-size:0.85rem;padding:0.45rem 0.75rem\">一覧更新</button>\n        </div>\n        <label class=\"muted\" for=\"adminCodeList\" style=\"font-size:0.78rem\">ID一覧（上ほど新しい）</label>\n        <textarea id=\"adminCodeList\" readonly rows=\"8\" style=\"margin-top:0.35rem\"></textarea>\n        <div class=\"toolbar\" style=\"margin-top:0.5rem\">\n          <input type=\"text\" id=\"adminRevokeCode\" placeholder=\"停止する8桁ID\" inputmode=\"numeric\" maxlength=\"8\" style=\"width:10rem\" />\n          <button type=\"button\" class=\"btn-danger\" id=\"btnAdminRevokeCode\" style=\"font-size:0.85rem;padding:0.45rem 0.75rem\">IDを停止</button>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <p id=\"appVersionBar\" class=\"muted\" style=\"font-size:0.82rem;margin:0 0 0.5rem\">バージョン …</p>\n  <h1>QR Magic（個人用）</h1>\n  <p class=\"muted\">8桁のログインIDで入ります。管理者IDは配布コードの発行と停止ができます。</p>\n\n  <div id=\"gate\" class=\"panel\">\n    <h2>ログインID</h2>\n    <p class=\"muted\">8桁の数字IDを入力してください（管理者IDも同じ欄で入力）。</p>\n    <input type=\"password\" id=\"gateToken\" placeholder=\"例: 12345678\" autocomplete=\"off\" />\n    <div class=\"toolbar\" style=\"margin-top:0.65rem\">\n      <button type=\"button\" class=\"btn-primary\" id=\"gateBtn\">開く</button>\n    </div>\n  </div>\n\n  <div id=\"app\" style=\"display:none\">\n    <div class=\"panel\">\n      <h2>テンプレート</h2>\n      <select id=\"templateSelect\" aria-label=\"テンプレート\" style=\"margin-top:0.35rem;margin-bottom:0.75rem\"></select>\n      <p class=\"muted\" style=\"font-size:.8rem;margin:0 0 .35rem\">切り替えはすぐサーバーに反映されます（キーワード欄の内容も一緒に保存されます）。</p>\n    </div>\n\n    <div class=\"panel\">\n      <h2>モード選択</h2>\n      <p class=\"muted\"><strong>永久化</strong>…一度永久化されたコードは、その後永久に表示内容は変わりません。</p>\n      <p class=\"muted\"><strong>リサイクル</strong>…キーワードが変更されるたびに表示内容が変わります。</p>\n      <div class=\"toolbar\">\n        <button type=\"button\" class=\"btn-secondary\" id=\"btnModeRecycle\">リサイクル</button>\n        <button type=\"button\" class=\"btn-secondary\" id=\"btnModeFrozen\">永久化</button>\n      </div>\n      <p id=\"modeLine\" class=\"muted\" style=\"margin-top:0.5rem\"></p>\n    </div>\n\n    <div class=\"panel\">\n      <h2>キーワード</h2>\n      <input type=\"text\" id=\"keyword\" placeholder=\"例: りんご\" autocomplete=\"off\" />\n      <div class=\"toolbar\">\n        <button type=\"button\" class=\"btn-primary\" id=\"saveBtn\">設定を保存</button>\n        <button type=\"button\" class=\"btn-secondary\" id=\"btnPreviewKeyword\">プレビュー</button>\n      </div>\n    </div>\n\n    <div class=\"panel\">\n      <h2>名刺用QR（1枚＝1URL）</h2>\n      <p class=\"muted\">先に<strong>URLだけ</strong>をたくさん作り、名刺に<strong>それぞれ違うQR</strong>を印刷しておきます。</p>\n      <p class=\"muted\"><strong>永久化</strong>で初回をずらすと名刺ごとに別の単語にできます。<strong>リサイクル</strong>は、まだ固定されていない名刺だけがキーワード変更に追従します。</p>\n      <p class=\"muted\">飛び先はプルダウンで選んだテンプレートを使います。1回あたり最大5000枚。</p>\n      <p id=\"ticketStatus\" class=\"muted\"></p>\n      <label class=\"muted\">枚数</label>\n      <input type=\"number\" id=\"ticketCount\" value=\"10\" min=\"1\" max=\"5000\" style=\"width:6rem;margin-left:.35rem\" />\n      <div class=\"toolbar\" style=\"margin-top:0.5rem\">\n        <button type=\"button\" class=\"btn-primary\" id=\"btnIssueTickets\">名刺用URLを発行</button>\n        <button type=\"button\" class=\"btn-danger\" id=\"btnClearTickets\">名刺用を全削除</button>\n      </div>\n      <label class=\"muted\" style=\"display:block;margin-top:0.65rem\">発行されたURL（1行1本・QRにしてください）</label>\n      <textarea id=\"ticketUrls\" readonly rows=\"10\" style=\"width:100%;font-size:.72rem;font-family:ui-monospace,monospace\"></textarea>\n    </div>\n  </div>\n\n  <p id=\"toast\" style=\"display:none;position:fixed;bottom:1rem;left:50%;transform:translateX(-50%);background:#111;color:#fff;padding:.6rem 1rem;border-radius:8px;z-index:120\"></p>\n\n  <script>\n    const LS = \"qr_magic_session_token\";\n    const gate = document.getElementById(\"gate\");\n    const appEl = document.getElementById(\"app\");\n\n    let sessionToken = localStorage.getItem(LS) || \"\";\n    let actor = null;\n    let state = null;\n    /** サーバー .env の PUBLIC_BASE_URL（https の観客用オリジン） */\n    let publicBaseUrl = \"\";\n\n    function toast(msg) {\n      const t = document.getElementById(\"toast\");\n      t.textContent = msg;\n      t.style.display = \"block\";\n      setTimeout(() => { t.style.display = \"none\"; }, 2200);\n    }\n\n    function authHeaders() {\n      return { Authorization: \"Bearer \" + sessionToken, \"Content-Type\": \"application/json\" };\n    }\n\n    async function api(path, opt = {}) {\n      const r = await fetch(path, { ...opt, headers: { ...authHeaders(), ...opt.headers } });\n      if (r.status === 401) {\n        localStorage.removeItem(LS);\n        sessionToken = \"\";\n        location.reload();\n        throw new Error(\"unauthorized\");\n      }\n      const j = await r.json().catch(() => ({}));\n      if (!r.ok) throw new Error(j.message || r.statusText);\n      return j;\n    }\n\n    function audienceOrigin() {\n      return (publicBaseUrl && publicBaseUrl.length > 0 ? publicBaseUrl : location.origin).replace(/\\/+$/, \"\");\n    }\n\n    function setSettingsFabVisible(on) {\n      const b = document.getElementById(\"btnOpenSettings\");\n      if (!b) return;\n      b.classList.toggle(\"settingsFab--visible\", !!on);\n    }\n\n    function isSettingsDrawerOpen() {\n      return document.getElementById(\"settingsDrawer\").classList.contains(\"settingsDrawer--open\");\n    }\n\n    function openSettingsDrawer() {\n      document.getElementById(\"settingsBackdrop\").classList.add(\"settingsBackdrop--open\");\n      document.getElementById(\"settingsDrawer\").classList.add(\"settingsDrawer--open\");\n      document.getElementById(\"btnOpenSettings\").setAttribute(\"aria-expanded\", \"true\");\n      document.getElementById(\"settingsBackdrop\").setAttribute(\"aria-hidden\", \"false\");\n      renderAdminCodePanel();\n      loadActiveTicketUrlsIntoDrawer();\n      loadTicketHistoryIntoDrawer();\n      loadAdminCodesIntoDrawer();\n    }\n\n    function closeSettingsDrawer() {\n      document.getElementById(\"settingsBackdrop\").classList.remove(\"settingsBackdrop--open\");\n      document.getElementById(\"settingsDrawer\").classList.remove(\"settingsDrawer--open\");\n      document.getElementById(\"btnOpenSettings\").setAttribute(\"aria-expanded\", \"false\");\n      document.getElementById(\"settingsBackdrop\").setAttribute(\"aria-hidden\", \"true\");\n    }\n\n    function isAdminActor() {\n      return actor && actor.role === \"admin\";\n    }\n\n    function renderAdminCodePanel() {\n      const panel = document.getElementById(\"adminCodePanel\");\n      panel.style.display = isAdminActor() ? \"block\" : \"none\";\n    }\n\n    async function loadActiveTicketUrlsIntoDrawer() {\n      const ta = document.getElementById(\"settingsUrlList\");\n      const meta = document.getElementById(\"settingsUrlMeta\");\n      meta.textContent = \"読み込み中…\";\n      ta.value = \"\";\n      try {\n        const d = await api(\"/api/tickets\");\n        const base = audienceOrigin();\n        const total = d.ticketCount != null ? d.ticketCount : 0;\n        const listed = d.listCount != null ? d.listCount : (d.paths || []).length;\n        meta.textContent =\n          \"全登録 \" +\n          total +\n          \" 本 · 一覧は未固定 \" +\n          listed +\n          \" 本（永久化済みは非表示）· 観客向けベース \" +\n          base;\n        const paths = d.paths || [];\n        ta.value = paths.map((p) => base + p).join(\"\\n\");\n      } catch (e) {\n        meta.textContent = \"\";\n        toast(String(e.message || e));\n      }\n    }\n\n    async function loadAdminCodesIntoDrawer() {\n      if (!isAdminActor()) return;\n      const meta = document.getElementById(\"adminCodeMeta\");\n      const ta = document.getElementById(\"adminCodeList\");\n      meta.textContent = \"読み込み中…\";\n      ta.value = \"\";\n      try {\n        const d = await api(\"/api/admin/codes\");\n        const rows = Array.isArray(d.codes) ? d.codes : [];\n        meta.textContent = \"総ID数 \" + rows.length + \"（管理者IDを含む）\";\n        ta.value = rows\n          .slice()\n          .reverse()\n          .map((r) => `${r.id}  ${r.role === \"admin\" ? \"管理者\" : \"ユーザー\"}  ${r.active ? \"有効\" : \"停止\"}`)\n          .join(\"\\n\");\n      } catch (e) {\n        meta.textContent = \"\";\n        toast(String(e.message || e));\n      }\n    }\n\n    async function issueCodesBulk() {\n      const n = parseInt(document.getElementById(\"adminIssueCount\").value, 10);\n      if (!Number.isFinite(n) || n < 1 || n > 5000) return toast(\"発行数は1〜5000\");\n      try {\n        const d = await api(\"/api/admin/codes/bulk\", { method: \"POST\", body: JSON.stringify({ count: n }) });\n        const ids = Array.isArray(d.ids) ? d.ids : [];\n        toast(ids.length + \"件発行しました\");\n        const ta = document.getElementById(\"adminCodeList\");\n        ta.value = ids.join(\"\\n\") + (ta.value ? \"\\n\" + ta.value : \"\");\n        loadAdminCodesIntoDrawer();\n      } catch (e) {\n        toast(String(e.message || e));\n      }\n    }\n\n    async function revokeCodeById() {\n      const id = String(document.getElementById(\"adminRevokeCode\").value || \"\").trim();\n      if (!/^\\d{8}$/.test(id)) return toast(\"8桁IDを入力してください\");\n      if (!confirm(id + \" を停止します。よろしいですか？\")) return;\n      try {\n        await api(\"/api/admin/codes/revoke\", { method: \"POST\", body: JSON.stringify({ id }) });\n        toast(\"停止しました\");\n        document.getElementById(\"adminRevokeCode\").value = \"\";\n        loadAdminCodesIntoDrawer();\n      } catch (e) {\n        toast(String(e.message || e));\n      }\n    }\n\n    function fmtDateTime(s) {\n      if (!s) return \"—\";\n      const d = new Date(s);\n      if (Number.isNaN(d.getTime())) return s;\n      return d.toLocaleString(\"ja-JP\");\n    }\n\n    async function loadTicketHistoryIntoDrawer() {\n      const meta = document.getElementById(\"settingsHistoryMeta\");\n      const sumTa = document.getElementById(\"settingsHistoryList\");\n      const evTa = document.getElementById(\"settingsRecentEvents\");\n      meta.textContent = \"読み込み中…\";\n      sumTa.value = \"\";\n      evTa.value = \"\";\n      try {\n        const d = await api(\"/api/tickets/history\");\n        meta.textContent =\n          \"URL \" + (d.ticketCount != null ? d.ticketCount : 0) + \" 本 / 合計読取 \" + (d.totalHits != null ? d.totalHits : 0) + \" 回\";\n        const rows = Array.isArray(d.tickets) ? d.tickets : [];\n        sumTa.value = rows\n          .map((r) => {\n            const latest = r.lastHitAt ? fmtDateTime(r.lastHitAt) : \"未読取\";\n            return `${r.path}  |  ${r.hitCount} 回  |  最終: ${latest}`;\n          })\n          .join(\"\\n\");\n        const evs = Array.isArray(d.recentEvents) ? d.recentEvents : [];\n        evTa.value = evs\n          .map((e) => `${fmtDateTime(e.at)}  ${e.path}  query=${e.query || \"-\"}`)\n          .join(\"\\n\");\n      } catch (e) {\n        meta.textContent = \"\";\n        toast(String(e.message || e));\n      }\n    }\n\n    async function downloadTicketQrsZip() {\n      try {\n        const r = await fetch(\"/api/tickets/qr-zip\", { headers: authHeaders() });\n        if (!r.ok) {\n          const j = await r.json().catch(() => ({}));\n          throw new Error(j.message || r.statusText || \"download failed\");\n        }\n        const blob = await r.blob();\n        const a = document.createElement(\"a\");\n        const cd = r.headers.get(\"content-disposition\") || \"\";\n        const m = cd.match(/filename=\\\"?([^\\\";]+)\\\"?/i);\n        const fn = (m && m[1]) || \"qr-tickets.zip\";\n        a.href = URL.createObjectURL(blob);\n        a.download = fn;\n        document.body.appendChild(a);\n        a.click();\n        a.remove();\n        setTimeout(() => URL.revokeObjectURL(a.href), 1000);\n        toast(\"ZIPをダウンロードしました\");\n      } catch (e) {\n        toast(String(e.message || e));\n      }\n    }\n\n    function buildUrl(template, query) {\n      const host = audienceOrigin();\n      return template.replaceAll(\"{host}\", host).replaceAll(\"{query}\", encodeURIComponent(query));\n    }\n\n    function ensurePresets() {\n      if (!state.templatePresets || !state.templatePresets.length) {\n        const t = state.serviceTemplate || \"https://www.google.com/search?q={query}\";\n        state.templatePresets = [{ label: \"Google\", template: t }];\n        state.activeTemplateIndex = 0;\n      }\n    }\n\n    function ticketKeywordMode() {\n      return state && state.ticketKeywordMode === \"recycle\" ? \"recycle\" : \"frozen\";\n    }\n\n    function renderTicketModeUi() {\n      const m = ticketKeywordMode();\n      document.getElementById(\"btnModeRecycle\").className = m === \"recycle\" ? \"btn-primary\" : \"btn-secondary\";\n      document.getElementById(\"btnModeFrozen\").className = m === \"frozen\" ? \"btn-danger\" : \"btn-secondary\";\n      document.getElementById(\"modeLine\").textContent =\n        m === \"frozen\"\n          ? \"いまのモード: 永久化（初回でそのURLの単語が永久に固定）\"\n          : \"いまのモード: リサイクル（未固定の名刺URLだけ、キーワード変更に追従）\";\n    }\n\n    /** 管理画面ではプリセットを編集しない。サーバーが返した一覧をそのまま送る用 */\n    function presetsFromState() {\n      ensurePresets();\n      return (state.templatePresets || []).map((p) => ({\n        label: String(p.label || \"\").trim().slice(0, 60) || \"プリセット\",\n        template: String(p.template || \"\").trim(),\n      }));\n    }\n\n    function renderTemplateBlock() {\n      ensurePresets();\n      const sel = document.getElementById(\"templateSelect\");\n      sel.innerHTML = \"\";\n      (state.templatePresets || []).forEach((p, i) => {\n        const o = document.createElement(\"option\");\n        o.value = String(i);\n        o.textContent = (p.label || `プリセット ${i + 1}`).slice(0, 60);\n        sel.appendChild(o);\n      });\n      const idx = Math.min(\n        Math.max(0, parseInt(state.activeTemplateIndex, 10) || 0),\n        Math.max(0, state.templatePresets.length - 1)\n      );\n      sel.value = String(idx);\n    }\n\n    function syncKeywordFromState() {\n      const q = (state.queries && state.queries[0]) || \"\";\n      document.getElementById(\"keyword\").value = q;\n    }\n\n    function renderAll() {\n      ensurePresets();\n      document.getElementById(\"ticketStatus\").textContent =\n        \"登録中の名刺用URL: \" + (state.ticketCount != null ? state.ticketCount : 0) + \" 本\";\n      renderTemplateBlock();\n      syncKeywordFromState();\n      renderTicketModeUi();\n    }\n\n    async function load() {\n      const data = await api(\"/api/state\");\n      publicBaseUrl = typeof data.publicBaseUrl === \"string\" ? data.publicBaseUrl.trim() : \"\";\n      actor = data.actor || null;\n      state = data.state;\n      renderAll();\n    }\n\n    async function putState(body) {\n      const data = await api(\"/api/state\", { method: \"PUT\", body: JSON.stringify(body) });\n      state = data.state;\n    }\n\n    async function saveKeywordAndTemplateSelection(extra) {\n      const kw = document.getElementById(\"keyword\").value.trim();\n      const presets = presetsFromState();\n      if (!presets.length) return toast(\"プリセットがありません\");\n      for (let i = 0; i < presets.length; i++) {\n        if (!presets[i].template.includes(\"{query}\")) {\n          return toast(\"プリセット \" + (i + 1) + \" に {query} を含めてください\");\n        }\n      }\n      await putState({\n        queries: [kw],\n        templatePresets: presets,\n        activeTemplateIndex:\n          extra && extra.activeTemplateIndex !== undefined\n            ? extra.activeTemplateIndex\n            : parseInt(document.getElementById(\"templateSelect\").value, 10) || 0,\n        ticketKeywordMode: ticketKeywordMode(),\n      });\n    }\n\n    async function save() {\n      try {\n        await saveKeywordAndTemplateSelection();\n        toast(\"保存しました\");\n        renderAll();\n      } catch (e) {\n        toast(String(e.message || e));\n      }\n    }\n\n    document.getElementById(\"templateSelect\").addEventListener(\"change\", async (e) => {\n      const idx = parseInt(e.target.value, 10);\n      if (!Number.isFinite(idx) || !state) return;\n      const kw = document.getElementById(\"keyword\").value.trim();\n      try {\n        const presets = presetsFromState();\n        if (!presets.every((p) => p.template.includes(\"{query}\"))) {\n          toast(\"各プリセットに {query} が必要です\");\n          renderAll();\n          return;\n        }\n        await putState({\n          queries: [kw],\n          templatePresets: presets,\n          activeTemplateIndex: idx,\n          ticketKeywordMode: ticketKeywordMode(),\n        });\n        toast(\"切り替えました\");\n        renderAll();\n      } catch (err) {\n        toast(String(err.message || err));\n        renderAll();\n      }\n    });\n\n    document.getElementById(\"btnPreviewKeyword\").onclick = () => {\n      ensurePresets();\n      const idx = parseInt(document.getElementById(\"templateSelect\").value, 10) || 0;\n      const tmpl = (state.templatePresets[idx] && state.templatePresets[idx].template) || \"\";\n      const kw = document.getElementById(\"keyword\").value.trim();\n      if (!tmpl.includes(\"{query}\")) return toast(\"{query} を含めてください\");\n      if (!kw) return toast(\"キーワードが空です\");\n      window.open(buildUrl(tmpl, kw), \"_blank\");\n    };\n\n    document.getElementById(\"btnOpenSettings\").onclick = () => {\n      if (!isSettingsDrawerOpen()) openSettingsDrawer();\n      else closeSettingsDrawer();\n    };\n    document.getElementById(\"btnCloseSettings\").onclick = () => closeSettingsDrawer();\n    document.getElementById(\"settingsBackdrop\").onclick = () => closeSettingsDrawer();\n    document.getElementById(\"btnRefreshUrlList\").onclick = () => {\n      if (isSettingsDrawerOpen()) loadActiveTicketUrlsIntoDrawer();\n    };\n    document.getElementById(\"btnRefreshHistory\").onclick = () => {\n      if (isSettingsDrawerOpen()) loadTicketHistoryIntoDrawer();\n    };\n    document.getElementById(\"btnDownloadQrZip\").onclick = () => downloadTicketQrsZip();\n    document.getElementById(\"btnAdminIssueCodes\").onclick = () => issueCodesBulk();\n    document.getElementById(\"btnAdminRefreshCodes\").onclick = () => loadAdminCodesIntoDrawer();\n    document.getElementById(\"btnAdminRevokeCode\").onclick = () => revokeCodeById();\n\n    document.addEventListener(\"keydown\", (e) => {\n      if (e.key === \"Escape\" && isSettingsDrawerOpen()) closeSettingsDrawer();\n    });\n\n    document.getElementById(\"gateBtn\").onclick = async () => {\n      const id = document.getElementById(\"gateToken\").value.trim();\n      if (!/^\\d{8}$/.test(id)) return toast(\"8桁のログインIDを入力してください\");\n      try {\n        const d = await fetch(\"/api/login\", {\n          method: \"POST\",\n          headers: { \"Content-Type\": \"application/json\" },\n          body: JSON.stringify({ id }),\n        }).then((r) => r.json());\n        if (!d.ok || !d.token) {\n          return toast(d.message || \"ログインに失敗しました\");\n        }\n        sessionToken = d.token;\n        localStorage.setItem(LS, sessionToken);\n        startApp();\n      } catch (e) {\n        toast(String(e.message || e));\n      }\n    };\n\n    document.getElementById(\"saveBtn\").onclick = () => save();\n\n    async function setTicketKeywordMode(mode) {\n      try {\n        const data = await api(\"/api/state\", {\n          method: \"PUT\",\n          body: JSON.stringify({ ticketKeywordMode: mode }),\n        });\n        state = data.state;\n        toast(mode === \"frozen\" ? \"永久化にしました\" : \"リサイクルにしました\");\n        renderAll();\n      } catch (e) {\n        toast(String(e.message || e));\n      }\n    }\n    document.getElementById(\"btnModeFrozen\").onclick = () => setTicketKeywordMode(\"frozen\");\n    document.getElementById(\"btnModeRecycle\").onclick = () => setTicketKeywordMode(\"recycle\");\n\n    document.getElementById(\"btnIssueTickets\").onclick = () => {\n      const n = parseInt(document.getElementById(\"ticketCount\").value, 10);\n      if (!Number.isFinite(n) || n < 1 || n > 5000) return toast(\"枚数は1〜5000\");\n      api(\"/api/tickets/bulk\", { method: \"POST\", body: JSON.stringify({ count: n }) })\n        .then((d) => {\n          state.ticketCount = d.ticketCount;\n          const base = audienceOrigin();\n          const lines = (d.tickets || []).map((x) => base + x.path);\n          document.getElementById(\"ticketUrls\").value = lines.join(\"\\n\");\n          toast(\"発行しました\");\n          renderAll();\n        })\n        .catch((e) => toast(String(e.message || e)));\n    };\n    document.getElementById(\"btnClearTickets\").onclick = () => {\n      if (!confirm(\"名刺用URLをすべて削除します。よろしいですか？\")) return;\n      api(\"/api/tickets/clear\", { method: \"POST\", body: JSON.stringify({ confirm: true }) })\n        .then((d) => {\n          state.ticketCount = d.ticketCount;\n          document.getElementById(\"ticketUrls\").value = \"\";\n          toast(\"削除しました\");\n          renderAll();\n        })\n        .catch((e) => toast(String(e.message || e)));\n    };\n\n    let pollTimer = null;\n    function startPublicUrlPoller() {\n      if (pollTimer) return;\n      let n = 0;\n      pollTimer = setInterval(async () => {\n        n++;\n        if (n > 45) {\n          clearInterval(pollTimer);\n          pollTimer = null;\n        }\n        try {\n          const r = await fetch(\"/api/public-qr-hint\");\n          const d = await r.json();\n          const base = (d.publicBaseUrl || \"\").replace(/\\/+$/, \"\");\n          if (base && state) {\n            const changed = base !== publicBaseUrl;\n            publicBaseUrl = base;\n            if (changed) renderAll();\n          }\n        } catch (_) {}\n      }, 2000);\n    }\n\n    async function startApp() {\n      try {\n        await load();\n        gate.style.display = \"none\";\n        appEl.style.display = \"block\";\n        setSettingsFabVisible(true);\n        startPublicUrlPoller();\n      } catch (e) {\n        localStorage.removeItem(LS);\n        sessionToken = \"\";\n        actor = null;\n        gate.style.display = \"block\";\n        appEl.style.display = \"none\";\n        setSettingsFabVisible(false);\n        closeSettingsDrawer();\n        toast(\"読み込み失敗: IDを確認してください\");\n      }\n    }\n\n    if (sessionToken) startApp();\n\n    (function loadAppVersion() {\n      fetch(\"/api/version\")\n        .then((r) => r.json())\n        .then((d) => {\n          const el = document.getElementById(\"appVersionBar\");\n          if (el && d.version) el.textContent = \"バージョン \" + d.version;\n        })\n        .catch(() => {\n          const el = document.getElementById(\"appVersionBar\");\n          if (el) el.textContent = \"\";\n        });\n    })();\n  </script>\n</body>\n</html>\n";
